import React from "react";

function Projects() {
  return (
    <>
      <main>
        <h1 className="text-center p-5">Projects</h1>
        <div className="container">
          <div className="row ">
            <div className="col-md-6">
              <img src="/assets/zerodhaclone.png" alt="Zerodha Clone"></img>
              <h3 className="text-center">Zerodha Clone</h3>
              <p></p>
            </div>
            <div className="col-md-6">
            </div>
          </div>
        </div>
      </main>
    </>
  );
}

export default Projects;
